+    private static func tokenize(_ text: String) -> [String] {
+        var tokens: [String] = []
+        var current = ""
+        var quote: Character?
+        var escapeNext = false
+
+        func flush() {
+            if !current.isEmpty {
+                tokens.append(current)
+                current = ""
+            }
+        }
+
+        for ch in text {
+            if escapeNext {
+                current.append(ch)
+                escapeNext = false
+                continue
+            }
+            if ch == "\\" && quote == "\"" {
+                escapeNext = true
+                continue
+            }
+            if ch == "\"" || ch == "'" {
+                if quote == ch {
+                    quote = nil
+                } else if quote == nil {
+                    quote = ch
+                } else {
+                    current.append(ch)
+                }
+                continue
+            }
+            if ch.isWhitespace && quote == nil {
+                flush()
+                continue
+            }
+            current.append(ch)
+        }
+        flush()
+        return tokens
+    }
